const invoices = $input.first().json.invoices || [];
const today = new Date();

const results = invoices.map(inv => {
  const dueDate = inv.due_date ? new Date(inv.due_date) : null;
  let daysOverdue = null;
  let stage = 'watch';

  if (dueDate) {
    const diffMs = today.getTime() - dueDate.getTime();
    daysOverdue = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    if (daysOverdue >= 14) stage = 'overdue-14';
    else if (daysOverdue >= 7) stage = 'overdue-7';
    else if (daysOverdue >= 3) stage = 'overdue-3';
    else if (daysOverdue === 0) stage = 'due-today';
    else stage = 'watch';
  } else {
    stage = 'missing-due-date';
  }

  return {
    json: {
      invoiceId: inv.id,
      invoiceNumber: inv.number,
      customerId: inv.customer_id,
      customerName: inv.customer_business_then_name,
      total: inv.total,
      dueDate: inv.due_date,
      daysOverdue,
      stage,
      pdfUrl: inv.pdf_url || null
    }
  };
});

return results.filter(r => ['due-today','overdue-3','overdue-7','overdue-14'].includes(r.json.stage));

const customer = $input.first().json.customer || {};
const prev = $('Classify Overdue Stage').first().json;

let recipientEmail = (customer.email || '').trim();
if (!recipientEmail && customer.contacts) {
  const contact = customer.contacts.find(c => c.email);
  if (contact) recipientEmail = contact.email.trim();
}

const stageMessages = {
  'due-today': {
    subject: `Invoice ${prev.invoiceNumber} is due today`,
    headline: 'A quick reminder that your invoice is due today.',
    closing: "If you've already scheduled payment, you can ignore this note."
  },
  'overdue-3': {
    subject: `Reminder: Invoice ${prev.invoiceNumber} is 3 days overdue`,
    headline: 'Your invoice is now 3 days overdue.',
    closing: 'Please reply if anything is blocking payment and we will help immediately.'
  },
  'overdue-7': {
    subject: `Action needed: Invoice ${prev.invoiceNumber} is 7 days overdue`,
    headline: 'Your invoice is now 7 days overdue and needs attention.',
    closing: 'Please confirm payment timing so we can keep your account in a healthy state.'
  },
  'overdue-14': {
    subject: `Final reminder: Invoice ${prev.invoiceNumber} is 14 days overdue`,
    headline: 'This is the final reminder before we escalate internally.',
    closing: 'Please reply today with a payment update or remittance confirmation.'
  }
};

const msg = stageMessages[prev.stage];

return [{
  json: {
    ...prev,
    recipientEmail,
    customerName: customer.business_name || customer.fullname || prev.customerName,
    noEmail: customer.no_email || false,
    subject: msg ? msg.subject : `Invoice ${prev.invoiceNumber} reminder`,
    headline: msg ? msg.headline : 'You have an outstanding invoice.',
    closing: msg ? msg.closing : 'Please arrange payment at your earliest convenience.'
  }
}];
